    const stage=$("#stageCard");if(stage&&!$(".u5-drag-hint",stage)){const h=document.createElement("div");h.className="u5-drag-hint";h.textContent="Katmanları sürükle • Fare tekeriyle ölçekle";stage.append(h)}
    ensureWardrobeLayer();document.body.insertAdjacentHTML("beforeend",worldMarkup());
    $("#u5Close").addEventListener("click",closeWorld);$("#u5Nav").addEventListener("click",navClick);$("#u5Content").addEventListener("click",contentClick);$("#u5Content").addEventListener("input",contentInput);$("#u5Content").addEventListener("change",contentInput);
    document.addEventListener("keydown",e=>{if(e.key==="Escape"&&$("#u5Overlay").classList.contains("open"))closeWorld()});
